  args: {
    initScreen: 'account'
  },
  parameters: {
    screen: 'main'
  },
  render: (args, context) => {
    const [open, setOpen] = useState(!!context.args.initScreen);
    return <div className="flex h-screen w-screen items-center justify-center bg-slate-700 bg-center">
        <button hidden={open} className="rounded-md bg-gradient-to-r from-pink-500 to-rose-500 px-6 py-3 font-bold text-white shadow-lg transition-all hover:scale-105" onClick={() => setOpen(!open)}>
          {open ? 'Close Settings' : 'Open Settings'}
        </button>
        {open && <SettingsMenu initScreen={context.args.initScreen} {...args} onClose={() => setOpen(false)} />}
      </div>;
  }
